import { useState, useEffect } from "react";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

export default function ClientManagement(){

const [showForm,setShowForm] = useState(false);
const [clients,setClients] = useState([]);
const [projects,setProjects] = useState([]);
const [search,setSearch] = useState("");
const [editId,setEditId] = useState(null);

const [formData,setFormData] = useState({
name:"",
co_owner:"",
phone:"",
address:"",
project:"",
floor:"",
room:"",
amount_paid:"",
payment_mode:"",
bank_name:"",
cheque_no:"",
installments:[]
});

// ================= LOAD =================
const fetchClients = async ()=>{
try{
const res = await fetch("http://localhost:5000/api/clients");
const data = await res.json();
setClients(data);
}catch(err){
console.log(err);
}
};

const fetchProjects = async ()=>{
try{
const res = await fetch("http://localhost:5000/api/projects");
const data = await res.json();
setProjects(data);
}catch(err){
console.log(err);
}
};

useEffect(()=>{
fetchClients();
fetchProjects();
},[]);

// ================= PROJECT =================
const selectedProject = projects.find(
p => p.name === formData.project
);

// ================= ROOMS =================
const generateRooms = (floor)=>{
if(!floor || !selectedProject) return [];

let rooms=[];
const totalRooms = selectedProject.roomsPerFloor || 10;

for(let i=1;i<=totalRooms;i++){
rooms.push(`${floor}${i.toString().padStart(2,"0")}`);
}
return rooms;
};

// ================= HANDLE INPUT =================
const handleChange = (e)=>{
const {name,value} = e.target;

if(name==="name" || name==="co_owner"){
const valid = value.replace(/[^a-zA-Z\s]/g,"");
setFormData({...formData,[name]:valid});
return;
}

if(name==="bank_name"){
const valid = value.replace(/[^a-zA-Z\s]/g,"");
setFormData({...formData,bank_name:valid});
return;
}

if(name==="cheque_no"){
const numeric = value.replace(/\D/g,"");
if(numeric.length > 10){
alert("Cheque number max 10 digits");
return;
}
setFormData({...formData,cheque_no:numeric});
return;
}

if(name==="address"){
const valid = value.replace(/[^a-zA-Z0-9\s]/g,"");
setFormData({...formData,address:valid});
return;
}

if(name==="phone"){
const numeric = value.replace(/\D/g,"");
if(numeric.length<=10){
setFormData({...formData,phone:numeric});
}
return;
}

if(name==="amount_paid"){
const num = Number(value);
if(num > 100000000){
alert("Max 10 Cr");
return;
}
}

setFormData({...formData,[name]:value});
};

// ================= INSTALLMENTS =================
const addInstallment = ()=>{
setFormData({
...formData,
installments:[...formData.installments,{amount:"",date:""}]
});
};

const handleInstallmentChange = (index,field,value)=>{
const updated = [...formData.installments];

if(field==="amount"){
const num = Number(value);
if(num > 100000000){
alert("Max 10 Cr");
return;
}
}

if(field==="date"){
if(index>0){
const prev = updated[index-1].date;
if(prev && new Date(value) <= new Date(prev)){
alert("Date must be after previous");
return;
}
}
}

updated[index][field]=value;
setFormData({...formData,installments:updated});
};

// ================= SAVE =================
const handleSubmit = async ()=>{
if(!formData.name) return alert("Enter name");

await fetch(
editId
? `http://localhost:5000/api/clients/${editId}`
: "http://localhost:5000/api/clients",
{
method: editId ? "PUT":"POST",
headers:{"Content-Type":"application/json"},
body:JSON.stringify(formData)
}
);

fetchClients();
setShowForm(false);
};

// ================= FLOORS =================
const floors = selectedProject
? Array.from({length:selectedProject.floors},(_,i)=>i+1)
: [];

// ================= BOOKED =================
const bookedRooms = clients
.filter(c =>
c.project === formData.project &&
String(c.floor) === String(formData.floor)
)
.map(c => c.room);

// ================= UI =================
return(

<div className="flex bg-gray-100 min-h-screen">

<Sidebar/>

<div className="flex-1 flex flex-col">

<Topbar/>

<div className="p-8">

<button onClick={()=>setShowForm(true)}
className="bg-orange-500 text-white px-6 py-3 rounded-xl mb-6">
+ Add Client
</button>

{showForm && (

<div className="bg-white p-8 rounded-2xl shadow">

<div className="grid grid-cols-2 gap-6">

{/* NAME */}
<div>
<label className="block mb-1">Owner Name</label>
<input name="name" value={formData.name} onChange={handleChange}
className="border px-4 py-3 rounded-xl w-full"/>
</div>

{/* CO OWNER */}
<div>
<label className="block mb-1">Co Owner</label>
<input name="co_owner" value={formData.co_owner} onChange={handleChange}
className="border px-4 py-3 rounded-xl w-full"/>
</div>

{/* PHONE */}
<div>
<label className="block mb-1">Phone</label>
<input name="phone" value={formData.phone} onChange={handleChange}
className="border px-4 py-3 rounded-xl w-full"/>
</div>

{/* ADDRESS */}
<div>
<label className="block mb-1">Address</label>
<input name="address" value={formData.address} onChange={handleChange}
className="border px-4 py-3 rounded-xl w-full"/>
</div>

{/* PROJECT */}
<div>
<label className="block mb-1">Project</label>
<select name="project" value={formData.project} onChange={handleChange}
className="border px-4 py-3 rounded-xl w-full">
<option value="">Select</option>
{projects.map(p=>(
<option key={p.id} value={p.name}>{p.name}</option>
))}
</select>
</div>

{/* FLOOR */}
<div>
<label className="block mb-1">Floor</label>
<select name="floor" value={formData.floor} onChange={handleChange}
className="border px-4 py-3 rounded-xl w-full">
<option value="">Select</option>
{floors.map(f=>(
<option key={f} value={f}>Floor {f}</option>
))}
</select>
</div>

{/* ROOM */}
<div>
<label className="block mb-1">Room</label>
<select name="room" value={formData.room} onChange={handleChange}
className="border px-4 py-3 rounded-xl w-full">
<option value="">Select</option>
{generateRooms(formData.floor).map(room=>{
const isBooked = bookedRooms.includes(room);
return(
<option key={room} value={room} disabled={isBooked}>
{room}
</option>
);
})}
</select>
</div>

{/* AMOUNT */}
<div>
<label className="block mb-1">Amount Paid</label>
<input type="number" name="amount_paid"
value={formData.amount_paid}
onChange={handleChange}
className="border px-4 py-3 rounded-xl w-full"/>
</div>

{/* PAYMENT */}
<div>
<label className="block mb-1">Payment Mode</label>
<select name="payment_mode"
value={formData.payment_mode}
onChange={handleChange}
className="border px-4 py-3 rounded-xl w-full">
<option value="">Select</option>
<option>Cash</option>
<option>Bank</option>
<option>Cheque</option>
</select>
</div>

{/* BANK */}
{(formData.payment_mode==="Bank" || formData.payment_mode==="Cheque") && (
<div>
<label className="block mb-1">Bank Name</label>
<input name="bank_name"
value={formData.bank_name}
onChange={handleChange}
className="border px-4 py-3 rounded-xl w-full"/>
</div>
)}

{/* CHEQUE */}
{formData.payment_mode==="Cheque" && (
<div>
<label className="block mb-1">Cheque No</label>
<input name="cheque_no"
value={formData.cheque_no}
onChange={handleChange}
className="border px-4 py-3 rounded-xl w-full"/>
</div>
)}

</div>

{/* INSTALLMENTS */}
<div className="mt-6">
<h2 className="font-semibold">Installments</h2>

{formData.installments.map((inst,i)=>(
<div key={i} className="flex gap-3 mt-2">
<input type="number" placeholder="Amount"
value={inst.amount}
onChange={(e)=>handleInstallmentChange(i,"amount",e.target.value)}
className="border px-3 py-2"/>

<input type="date"
value={inst.date}
onChange={(e)=>handleInstallmentChange(i,"date",e.target.value)}
className="border px-3 py-2"/>
</div>
))}

<button onClick={addInstallment}
className="bg-blue-500 text-white px-4 py-2 mt-2 rounded">
+ Add Installment
</button>
</div>

</div>
)}

</div>
</div>
</div>

);
}
